    public function order($chainID,$dataArray)
    {
        if(!isset($chainID) || empty($chainID))
        {
            $status['status'] = false;
            $status['message'] = "ChainID is not found in the api url";
            return $status;
        }
        //check chainID 
        $chainConf = self::checkConfig($chainID);
        if(empty($chainConf))
        {
            $status['status'] = false;
            $status['message'] = "Invalid chainID";
            return $status;
        }
        $chainID = $chainConf[0]["chainID"];
        $timezone = $chainConf[0]["timezone"];
        $enableStockLedger = $chainConf[0]["enableStockLedger"];
        if(!$enableStockLedger)
        {
            $status['status'] = false;
            $status['message'] = "Stock ledger is not enabled for this chain";
            return $status;
        }
        $industry = $chainConf[0]['industry'];
        $stockLedgerSummaryTable = Constants::getChainInventoryTableName($chainID,'stockLedgerSummary');
        $stockLedgerDetailTable = Constants::getChainInventoryTableName($chainID,'stockLedgerDetail');
        $orderSummaryTable = Constants::getChainTableName($chainID,'orderSummary');
        $orderDetailTable = Constants::getChainTableName($chainID,'orderDetail');
        $orderComboProductsTable = Constants::getChainTableName($chainID,'orderComboProducts');
        $orderModifiersTable = Constants::getChainTableName($chainID,'orderModifiers');
        $productPricesTable = Constants::getChainLevelProductsName($chainID,'productPrices');
        $modifiersTable = Constants::getChainLevelProductsName($chainID,"modifiers");
        $chainSettingsTable = Constants::getGlobalTableName('chainSettings');
		$chainSettingsDetail = convertToArray(DB::table($chainSettingsTable)->where('chainRefID',$chainID)->select('enableModifier')->get());
