private static function getAccountType($storeID, $accountID){

    $accountsTable = Constants::getTableName($storeID,"accountIDs");
    $globalsTable = Constants::getGlobalTableName("globalTypeValues");
    $getAccountType = convertToArray(DB::select(DB::raw("SELECT value FROM $globalsTable WHERE ID = (SELECT accountTypeValueID FROM $accountsTable WHERE accountID = ?)"),[$accountID]));
    $accountType = $getAccountType[0]['value'];

    return $accountType;
}

