    public static function addStorePaymentSettings(Request $request)
    {
		$result = $request->getContent();
		if (isJson($result) == FALSE) {
			$client = "Invalid Data";
			return response()->json($client,422,[],JSON_NUMERIC_CHECK);
		}
		$data = convertToArray(json_decode($result));
		$v = new V($data);
		$v->rule("required",array("storeID", "paymentTypeID"));
		if (!$v->validate()) {
			$status["status"] = false;
			$status["message"] = $v->errors();
			return response()->json($status,422,[],JSON_NUMERIC_CHECK);
		}
		if ($request->header('userID') != null) {
			$data["userID"] = $request->header('userID');
		}
		$data["source"] = "WEBV2";
		$response = Admin::addStorePaymentSettings($data);
		return response()->json($response,200,[],JSON_NUMERIC_CHECK);
	}

