async function formatPaymentList(connection, payments, piSummary, basicDetails) {

	const tableGlobalPaymentAccountMapping = "globalTypePaymentAccountIDMapping";
	const tableGlobalValueTypes            = "globalTypeValues";
	const tableRestAccountID = newTableName("chain1_accountIDs", "chain1", `chain${basicDetails.chainID}`);
	const tableRestPaymentSettings = newTableName("store1_paymentSettings", "store1", `store${basicDetails.storeID}`);

	// get payment types
	const query = `SELECT 
			DISTINCT B.accountTypeValueID,A.accountID,A.accountName,B.paymentTypeValueID,D.value AS 'key',D.printName AS paymentsUIDisplayText,C.isSystemIntegrated, E.value AS accountType
		FROM ${tableRestAccountID} AS A 
			INNER JOIN ${tableGlobalPaymentAccountMapping} AS B ON A.accountTypeValueID = B.accountTypeValueID
			INNER JOIN ${tableRestPaymentSettings} AS C ON B.paymentTypeValueID = C.paymentTypeID
			INNER JOIN ${tableGlobalValueTypes} AS D ON C.paymentTypeID = D.ID AND D.typeID = 7 
			INNER JOIN ${tableGlobalValueTypes} AS E ON E.ID = B.accountTypeValueID AND E.typeID = 1
		WHERE C.isActive = 1 
		GROUP BY B.accountTypeValueID,B.paymentTypeValueID ORDER BY C.paymentTypeID`;

	const storePayments = await connection.query(query);
	// sample output
	// [{"accountTypeValueID":6,"accountID":2,"accountName":"CashReceived","paymentTypeValueID":101,"key":"PAYMENT_CASH","paymentsUIDisplayText":"Cash","isSystemIntegrated":0},{"accountTypeValueID":7,"accountID":3,"accountName":"CardReceived","paymentTypeValueID":102,"key":"PAYMENT_CARD","paymentsUIDisplayText":"Card","isSystemIntegrated":0},{"accountTypeValueID":205,"accountID":13,"accountName":"StandardCustomerAccount","paymentTypeValueID":206,"key":"PAYMENT_CREDIT","paymentsUIDisplayText":"Credit Sale","isSystemIntegrated":0},{"accountTypeValueID":217,"accountID":16,"accountName":"UPIReceived","paymentTypeValueID":218,"key":"PAYMENT_UPI","paymentsUIDisplayText":"UPI","isSystemIntegrated":0},{"accountTypeValueID":205,"accountID":13,"accountName":"StandardCustomerAccount","paymentTypeValueID":260,"key":"PAYMENT_CREDIT_NOTE","paymentsUIDisplayText":"Credit Note","isSystemIntegrated":0},{"accountTypeValueID":408,"accountID":35,"accountName":"BEEPKART_RCVDReceived","paymentTypeValueID":407,"key":"PAYMENT_BEEPKART","paymentsUIDisplayText":"BeepKart Payment","isSystemIntegrated":0}]

	// based on received payments and storePayments, create the payment list
	// sample 
	// {"accountId":2,"accountName":"CashReceived","accountType":"ACC_CASH_RECD","acquiringBankCode":"","amount":0,"approvalCode":"","bankRRN":"","batchID":"","batchNo":"","cardHolderName":"","cardType":"","creditNoteExpiryDays":0,"creditNoteID":-1,"expDate":"","isNoInvoiceSale":0,"isSignatureRequired":0,"lastFourDigits":"","manualEntry":0,"newAmount":0,"orderTimeLocal":"","partType":"","partyID":-1,"partyName":"","paymentSubID":1,"paymentTerminal":"","paymentType":"PAYMENT_CASH","pinVerified":0,"posDate":"2024-04-25","purchaseOrderID":"","roc":"","shortAmount":0,"transactionID":"","transactionType":"","uniqueReferenceID":"","userID":-1,"userName":"Admin_beepkart","walletType":""}
	return payments.map(payment => {
		const storePayment = storePayments.find(storePayment => storePayment.key === payment.paymentType);

    $listOfChainsTable = Constants::getGlobalTableName("listOfChains");
    $chainSettingsTable = Constants::getGlobalTableName('chainSettings');
    $listOfStoresTable = Constants::getGlobalTableName("listOfStores");
    $globalTypeValuesTable = Constants::getGlobalTableName("globalTypeValues");

    $chainID = convertToArray(DB::table($listOfStoresTable)->where('storeID',$storeID)->select('chainID')->get());
    $chainID = $chainID[0]['chainID'];
    $channelsTable = Constants::getChainTableName($chainID,"channels");
    $channelStoreMapTable = Constants::getChainTableName($chainID, "channelStoreMap");
    $channelPaymentMapTable = Constants::getChainTableName($chainID, "channelPaymentMap");

    $chainDetail = convertToArray(DB::table($listOfChainsTable)->where('chainID', $chainID)->value("isActive"));
    $isChannelEnabled = convertToArray(DB::table($chainSettingsTable)->where("chainRefID", $chainID)->value("enableChannelManagement"));
    $paymentModes = convertToArray(DB::table($globalTypeValuesTable)->where('typeID', 7)->get());
    $paymentModesMap = [];
    foreach ($paymentModes as $paymentMode) {
        $paymentModesMap[$paymentMode['ID']] = $paymentMode['value'];
    }

    if ($chainDetail == 0) {
        $status["status"] = false;
        $status["message"] = "invalid chain ID";
        return $status;
    }
    if($isChannelEnabled == 0){
        $status["status"] = false;
        $status["message"] = "Channel not enabled";
        return $status;
    }
    $storeChannels = convertToArray(DB::table($channelStoreMapTable)->where('storeID',$storeID)->where('isActive',1)->select('channelID')->get());
    $channelIDs = array_column($storeChannels, 'channelID');

    $paymentModes = convertToArray(DB::table($channelPaymentMapTable)->whereIn('channelID',$channelIDs)->where("isActive",1)->get());

    $channels = convertToArray(DB::table($channelsTable)->whereIn('channelID',$channelIDs)->where("isActive",1)->get());

    // add respective paymentModes to each channel
    foreach ($channels as &$channel) {
        $channelID = $channel['channelID'];
        $channel['paymentModes'] = [];
        foreach ($paymentModes as $paymentMode) {
            if ($paymentMode['channelID'] == $channelID) {
                $channel['paymentModes'][] = $paymentModesMap[$paymentMode['paymentTypeValueID']];
            }
        }
        $channel['paymentModes'] = implode(',', $channel['paymentModes']);
        $channel["applyChargesforChannelOrders"] = $channel["applyChargesForChannelOrders"];
    }

    $status["status"] = true;
    $status["data"] = $channels;
    return $status;
}

